    if (n <= 0) return 0;
    let maxWeight = 0;
    for (let e of edges) {
        if (e[2] > maxWeight) maxWeight = e[2];
    }
    let low = 0;
    let high = maxWeight + 1;

    const feasible = (x: number): boolean => {
        let parent: number[] = new Array(n);
        let rank: number[] = new Array(n).fill(0);
        for (let i = 0; i < n; i++) {
            parent[i] = i;
        }

        const find = (a: number): number => {
            let path = [];
            let cur = a;
            while (parent[cur] !== cur) {
