function solve(n: number, edges: number[][], k: number): number {
    if (k >= n) {
        return 0;
    }

    const groupMap = new Map<number, [number, number][]>();
    const distinctWeightsSet = new Set<number>();
    for (const edge of edges) {
        const u = edge[0];
        const v = edge[1];
        const w = edge[2];
        distinctWeightsSet.add(w);
        if (!groupMap.has(w)) {
            groupMap.set(w, []);
        }
        groupMap.get(w)!.push([u, v]);
    }

    const distinctWeights = Array.from(distinctWeightsSet).sort((a, b) => a - b);

    const parent: number[] = Array.from({ length: n }, (_, i) => i);
    const rank: number[] = new Array(n).fill(0);
    let comp_count = n;

    const find = (x: number): number => {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    const union = (x: number, y: number): boolean => {
        const rx = find(x);
        const ry = find(y);
        if (rx === ry) {
            return false;
        }
        if (rank[rx] < rank[ry]) {
            parent[rx] = ry;
        } else if (rank[rx] > rank[ry]) {
            parent[ry] = rx;
        } else {
            parent[ry] = rx;
            rank[rx]++;
        }
        comp_count--;
        return true;
    };

    for (const w of distinctWeights) {
        const edgeList = groupMap.get(w) || [];
        for (const [u, v] of edgeList) {
            union(u, v);
        }
        if (comp_count <= k) {
            return w;
        }
    }

    return distinctWeights[distinctWeights.length - 1];
}
```

